import type { ChartUnit } from '../../../core/types/chart-unit.js';
export interface HistogramBin {
    /**
     * The start of the bin or bucket
     */
    from: number;
    /**
     * The end of the bin or bucket
     */
    to: number;
    /**
     * The value, better known as "frequency"
     */
    value: number;
}
export interface HistogramSeries {
    /**
     * The histogram series data to be graphed by the component
     */
    bins: HistogramBin[];
    /**
     * The name for the histogram series
     */
    name: string;
    /**
     * Unit token for the values in the y-axis of the histogram series
     */
    unit?: ChartUnit;
    /**
     * The color to be applied to the series
     */
    color?: string;
}
